long long splitArray(vector<int>& nums, int k) {
    long long low = 0;
    long long high = 0;

    for (int num : nums) {
        low = max(low, (long long)num);
        high += num;
    }

    long long result = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;

        if (canSplit(nums, k, mid)) {
            result = mid;
            high = mid - 1; // try smaller maximum
        } else {
            low = mid + 1;  // need larger maximum
        }
    }

    return result;
}

// Optional helper function
bool canSplit(vector<int>& nums, int k, long long mid) {
    int count = 1;
    long long sum = 0;

    for (int num : nums) {
        if (sum + num > mid) {
            count++;
            sum = num;
            if (count > k) return false;
        } else {
            sum += num;
        }
    }
    return true;
}
