def is_valid_split(nums, k, max_sum):

    count = 1
    total = 0
    for num in nums:
        if total + num > max_sum:
            count += 1
            total = num
            if count > k:
                return False
        else:
            total += num
    return True


def split_array(nums, k):

    low = max(nums)       # at least the largest element
    high = sum(nums)      # at most the total sum
    result = high

    while low <= high:
        mid = (low + high) // 2
        if is_valid_split(nums, k, mid):
            result = mid
            high = mid - 1
        else:
            low = mid + 1

    return result

