long long splitArray(int* nums, int N, int K) {
    long long low = 0;
    long long high = 0;

    for (int i = 0; i < N; i++) {
        if (nums[i] > low) low = nums[i];
        high += nums[i];
    }

    long long result = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (canSplit(nums, N, K, mid)) {
            result = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return result;
}

int canSplit(int* nums, int N, int K, long long mid) {
    int count = 1;
    long long sum = 0;

    for (int i = 0; i < N; i++) {
        if (sum + nums[i] > mid) {
            count++;
            sum = nums[i];
            if (count > K) return 0;
        } else {
            sum += nums[i];
        }
    }

    return 1;
}

