class Solution {
public long splitArray(int[] nums,int K) {
       long low = 0;
       long high = 0;

       for (int num : nums) {
           low = Math.max(low, num);
           high += num;
       }

       long result = high;

       while (low <= high) {
           long mid = low + (high - low) / 2;
           if (canSplit(nums, K, mid)) {
               result = mid;
               high = mid - 1;
           } else {
               low = mid + 1;
           }
       }

       return result;
   }

   static boolean canSplit(int[] nums, int k, long mid) {
       int count = 1;
       long sum = 0;

       for (int num : nums) {
           if (sum + num > mid) {
               count++;
               sum = num;
               if (count > k) return false;
           } else {
               sum += num;
           }
       }
       return true;
   }
}

