// Function to check if we can split into <= k subarrays with max sum <= mid
function isValidSplit(nums, k, maxSum) {
    let count = 1;
    let total = 0;

    for (let num of nums) {
        if (total + num > maxSum) {
            count++;
            total = num;
            if (count > k) return false;
        } else {
            total += num;
        }
    }
    return true;
}

// Main function: binary search for minimized largest sum
function splitArray(nums, k) {
    let low = Math.max(...nums);
    let high = nums.reduce((a, b) => a + b, 0);
    let result = high;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (isValidSplit(nums, k, mid)) {
            result = mid;
            high = mid - 1; // try smaller max
        } else {
            low = mid + 1;  // need bigger max
        }
    }

    return result;
}
